mapper.select:
SELECT TO_CHAR(o.ORDER_DATE, 'YYYY-MM') AS settlementMonth, NVL(SUM(o.TOTAL_AMOUNT), 0) AS gmv, NVL(SUM(o.COUPON_DISCOUNT), 0) AS couponDiscount, NVL(SUM(o.POINT_DISCOUNT), 0) AS pointUsed, NVL(SUM(ROUND(o.TOTAL_AMOUNT * r.COMMISSION_RATE / 100)), 0) AS commission, NVL(SUM(o.TOTAL_AMOUNT - ROUND(o.TOTAL_AMOUNT * r.COMMISSION_RATE / 100)), 0) AS partnerPayout, NVL(SUM(ROUND(o.TOTAL_AMOUNT * r.COMMISSION_RATE / 100)) - SUM(o.COUPON_DISCOUNT) - SUM(o.POINT_DISCOUNT), 0) AS netProfit, COUNT(DISTINCT r.PARTNER_ID) AS partnerCount, 'DONE' AS status, 'badge-done' AS statusBadgeClass, '완료' AS statusLabel FROM ORDERS o INNER JOIN ORDER_DETAIL od ON o.ORDER_ID = od.ORDER_ID INNER JOIN RESERVATION r ON od.RESERVATION_ID = r.RESERVATION_ID WHERE o.STATUS = 'SUCCESS' AND TO_CHAR(o.ORDER_DATE, 'YYYY') = TO_CHAR(#{year})
AND TO_CHAR(o.ORDER_DATE, 'MM') = #{month}
GROUP BY TO_CHAR(o.ORDER_DATE, 'YYYY-MM') ORDER BY TO_CHAR(o.ORDER_DATE, 'YYYY-MM') DESC
